  "x": z.number().default(0).describe("The target x coordinate to move to"),
  "z": z.number().default(0).describe("The target z coordinate to move to"),
  "radius": z.number().default(2).describe("The acceptable distance from the target coordinates")
})",
  "executionArgs": {
