  },
  "code": "const targetX = args.x;
const targetZ = args.z;
const radius = args.radius;
const targetY = bot.entity ? Math.floor(bot.entity.position.y) : 64;

startBackgroundSkill(bot, 'move_to_spawn_midpoint', async function (token) {
  const movements = new Movements(bot);
  movements.canDig = false; // Safety setting for regrouping
  bot.pathfinder.setMovements(movements);

  // GoalNear is used to reach the proximity of the target coordinates.
  // Since we don't know the exact Y, we use the current Y or a reasonable guess.
  // Pathfinder will attempt to find a valid path to the surface at those XZ coordinates.
  const goal = new goals.GoalNear(targetX, targetY, targetZ, radius);

  try {
    await bot.pathfinder.goto(goal);
    if (!token.cancelled) {
      bot.chat("Arrived at spawn midpoint regrouping area.");
    }
  } catch (error) {
    if (!token.cancelled) {
      console.error("Pathfinding to spawn midpoint failed:", error);
    }
  }
});

return "<MOVING>: Moving to coordinates (x:" + targetX + ", z:" + targetZ + ") within a radius of " + radius + ".";"
}

