  "code": "const targetX = args.x;
const targetZ = args.z;
const radius = args.radius;
const targetY = Math.floor(bot.entity.position.y);

startBackgroundSkill(bot, 'move_to_midpoint', async function (token) {
  const movements = new Movements(bot);
  movements.canDig = false;
  bot.pathfinder.setMovements(movements);

  const goal = new goals.GoalNear(targetX, targetY, targetZ, radius);

  try {
    while (!token.cancelled && bot.health > 0 && Boolean(bot.entity)) {
      // Check if we are already within radius of XZ
      const dx = bot.entity.position.x - targetX;
      const dz = bot.entity.position.z - targetZ;
      const distanceXZ = Math.sqrt(dx * dx + dz * dz);

      if (distanceXZ <= radius) {
        return;
      }

      if (bot.physicsEnabled) {
        await bot.pathfinder.goto(goal);
        // Exit loop if we successfully arrived
        break;
      }

      // Small delay to prevent tight loop if physics disabled
      await new Promise(function (resolve) { setTimeout(resolve, 100); });
    }
  } catch (error) {
    if (!token.cancelled) {
      console.error('Midpoint movement error:', error);
    }
  }
});

return "<MOVING>: Moving to midpoint at X:" + targetX + " Z:" + targetZ + " with radius " + radius + ".";"
}

{
  "parameters": "z.object({ maxTicks: z.number().default(80).describe("Duration of the kiting/melee behavior in server ticks."), preferredDistance: z.number().default(8).describe("The distance to maintain from targets when using a bow."), retreatBlocks: z.number().default(6).describe("The distance to back up after a melee attack to maintain spacing or lead hostiles.") })",
  "executionArgs": {
    "maxTicks": 80,
    "preferredDistance": 8,
    "retreatBlocks": 6
  },
  "code": "const maxTicks = args.maxTicks;
const preferredDistance = args.preferredDistance;
const retreatBlocks = args.retreatBlocks;

startBackgroundSkill(bot, 'kite_bot1', async function (token) {
  const movements = new Movements(bot);
  movements.canDig = false;
  bot.pathfinder.setMovements(movements);
  let ticks = 0;

  const getWeapon = function () {
    const sword = bot.inventory.items().find(function (item) { return item.name.includes('sword'); });
    const bow = bot.inventory.items().find(function (item) { return item.name === 'bow'; });
    const arrows = bot.inventory.items().find(function (item) { return item.name === 'arrow'; });
    return { sword: sword, bow: (arrows ? bow : null) };
  };

  while (ticks < maxTicks && !token.cancelled && bot.entity && bot.health > 0) {
    if (!bot.physicsEnabled) {
      await new Promise(function (res) { setTimeout(res, 100); });
      continue;
    }

    // Hunt nearest hostile within 32 blocks
    const target = bot.nearestEntity(function (e) {
      return (e.type === 'hostile' || e.type === 'mob') && e.position.distanceTo(bot.entity.position) < 32;
    });

    if (target) {
      const equipment = getWeapon();
      const dist = bot.entity.position.distanceTo(target.position);

      if (dist < 4 && equipment.sword) {
        // Melee Forward Priority: Close in and strike
        await bot.equip(equipment.sword, 'hand');
        await bot.lookAt(target.position.offset(0, 1.5, 0));
        bot.attack(target);
        // Kiting maneuver: back up to lead the target toward Bot2 or clear space
        const retreatDir = bot.entity.position.minus(target.position).normalize().scaled(retreatBlocks);
        const goalPos = bot.entity.position.plus(retreatDir);
        bot.pathfinder.setGoal(new goals.GoalNear(goalPos.x, goalPos.y, goalPos.z, 1));
      } else if (dist > 4 && equipment.bow) {
        // Ranged support
        await bot.equip(equipment.bow, 'hand');
        await bot.lookAt(target.position.offset(0, 1.5, 0));
        bot.activateItem();
        await new Promise(function (res) { setTimeout(res, 1100); });
        bot.deactivateItem();

        // Tactical spacing
        if (dist < preferredDistance) {
          const retreatDir = bot.entity.position.minus(target.position).normalize().scaled(preferredDistance);
          const goalPos = target.position.plus(retreatDir);
          bot.pathfinder.setGoal(new goals.GoalNear(goalPos.x, goalPos.y, goalPos.z, 2));
        } else {
          bot.pathfinder.setGoal(new goals.GoalFollow(target, preferredDistance));
        }
      } else {
        // Melee closing logic
        bot.pathfinder.setGoal(new goals.GoalFollow(target, 2));
      }
    } else {
      // No hostiles found; maintain proximity to partner Bot2
      const partner = bot.nearestEntity(function (e) {
        return e.type === 'player' && e.username !== bot.username;
      });
      if (partner) {
        bot.pathfinder.setGoal(new goals.GoalFollow(partner, 4));
      }
    }

    // Wait for the next decision cycle
    await new Promise(function (res) { setTimeout(res, 400); });
    ticks += 8;
  }

  bot.pathfinder.setGoal(null);
});

return "<KITING>: Bot1 has engaged combat protocol (melee forward/kite combo) for " + maxTicks + " ticks.";"
}

