  "code": "const weaponName = args.weapon;
const targetId = args.target_id;
const findItem = function (name) {
  const normalized = name.toLowerCase().replace(/_/g, ' ');
  return bot.inventory.items().find(function (item) {
    return item.name.toLowerCase().includes(name.toLowerCase()) || (item.displayName && item.displayName.toLowerCase().replace(/_/g, ' ').includes(normalized));
  });
};
const initialWeapon = findItem(weaponName);
if (!initialWeapon) {
  return '<MISSING_ITEM>: I do not have ' + weaponName + ' in my inventory.';
}
startBackgroundSkill(bot, 'melee_attack_forward', async function (token) {
  const movements = new Movements(bot);
  movements.canDig = false;
  bot.pathfinder.setMovements(movements);
  while (!token.cancelled && bot.health > 0 && Boolean(bot.entity)) {
    if (!bot.physicsEnabled) {
      await new Promise(function (r) {
        setTimeout(r, 100);
      });
      continue;
    }
    let target = targetId ? bot.entities[targetId] : null;
    if (!target) {
      target = bot.nearestEntity(function (e) {
        if (e.id === bot.entity.id) return false;
        if (e.type !== 'mob' && e.type !== 'player') return false;
        if (e.username === 'Bot2' || e.name === 'Bot2' || e.id === 1) return false;
        return true;
      });
    }
    if (!target || !target.isValid) {
      if (bot.pathfinder.goal) bot.pathfinder.stop();
      await new Promise(function (r) {
        setTimeout(r, 500);
      });
      continue;
    }
    const held = bot.heldItem;
    if (!held || !held.name.includes(weaponName)) {
      const w = findItem(weaponName);
      if (w) await bot.equip(w, 'hand');
    }
    const dist = bot.entity.position.distanceTo(target.position);
    if (!bot.pathfinder.goal || !bot.pathfinder.goal.entity || bot.pathfinder.goal.entity.id !== target.id) {
      bot.pathfinder.setGoal(new goals.GoalFollow(target, 2.5));
    }
    if (dist <= 3.8) {
      await bot.lookAt(target.position.offset(0, target.height * 0.8, 0), true);
      bot.attack(target);
      await new Promise(function (r) {
        setTimeout(r, 650);
      });
    } else {
      await new Promise(function (r) {
        setTimeout(r, 50);
      });
    }
  }
  bot.pathfinder.stop();
});
return '<ATTACKING>: Aggressively pursuing targets with ' + weaponName + '.';"
